#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
my $next = $cgi->param('next');

if (defined $next && $next =~ m!^https?://[\w.:/-]+/?$!) {
    print "Location: $next\n\n";
} else {
    print "Location: /default.html\n\n";  # Default redirect if 'next' is invalid or missing
}